window.KJV1769_STRONG_BOOKS["Lam"] = {"osis":"Lam","book":"예레미야애가","verses":{"1:1":{"text":"How doth the city sit solitary, that was full of people! how is she become as a widow! she that was great among the nations, and princess among the provinces, how is she become tributary!","words":[["H5892","How doth the city",0,17],["H3427","sit",18,21],["H0910","solitary",22,30],["H7227","that was full",32,45],["H5971","of people",46,55],["H0490","how is she become as a widow",57,85],["H7227","she that was great",87,105],["H1471","among the nations",106,123],["H8282","and princess",125,137],["H4082","among the provinces",138,157],["H4522","how is she become tributary",159,186]]},"1:2":{"text":"She weepeth sore in the night, and her tears are on her cheeks: among all her lovers she hath none to comfort her: all her friends have dealt treacherously with her, they are become her enemies.","words":[["H1058","She weepeth",0,11],["H1058","sore",12,16],["H3915","in the night",17,29],["H1832","and her tears",31,44],["H3895","are on her cheeks",45,62],["H0157","among all her lovers",64,84],["H5162","she hath none to comfort",85,109],["H7453","her: all her friends",110,130],["H0898","have dealt treacherously",131,155],["H0341","with her, they are become her enemies",156,193]]},"1:3":{"text":"Judah is gone into captivity because of affliction, and because of great servitude: she dwelleth among the heathen, she findeth no rest: all her persecutors overtook her between the straits.","words":[["H3063","Judah",0,5],["H1540","is gone into captivity",6,28],["H6040","because of affliction",29,50],["H7230","and because of great",52,72],["H5656","servitude",73,82],["H3427","she dwelleth",84,96],["H1471","among the heathen",97,114],["H4672","she findeth",116,127],["H4494","no rest",128,135],["H7291","all her persecutors",137,156],["H5381","overtook",157,165],["H4712","her between the straits",166,189]]},"1:4":{"text":"The ways of Zion do mourn, because none come to the solemn feasts: all her gates are desolate: her priests sigh, her virgins are afflicted, and she is in bitterness.","words":[["H1870","The ways",0,8],["H6726","of Zion",9,16],["H0057","do mourn",17,25],["H0935","because none come",27,44],["H4150","to the solemn feasts",45,65],["H8179","all her gates",67,80],["H8074","are desolate",81,93],["H3548","her priests",95,106],["H0584","sigh",107,111],["H1330","her virgins",113,124],["H3013","are afflicted",125,138],["H4843","and she is in bitterness",140,164]]},"1:5":{"text":"Her adversaries are the chief, her enemies prosper; for the LORD hath afflicted her for the multitude of her transgressions: her children are gone into captivity before the enemy.","words":[["H6862","Her adversaries",0,15],["H7218","are the chief",16,29],["H0341","her enemies",31,42],["H7951","prosper",43,50],["H3068","for the LORD",52,64],["H3013","hath afflicted",65,79],["H7230","her for the multitude",80,101],["H6588","of her transgressions",102,123],["H5768","her children",125,137],["H1980","are gone",138,146],["H7628","into captivity",147,161],["H6440","before",162,168],["H6862","the enemy",169,178]]},"1:6":{"text":"And from the daughter of Zion all her beauty is departed: her princes are become like harts that find no pasture, and they are gone without strength before the pursuer.","words":[["H1323","And from the daughter",0,21],["H6726","of Zion",22,29],["H1926","all her beauty",30,44],["H3318","is departed",45,56],["H8269","her princes",58,69],["H0354","are become like harts",70,91],["H4672","that find",92,101],["H4829","no pasture",102,112],["H3212","and they are gone",114,131],["H3581","without strength",132,148],["H6440","before",149,155],["H7291","the pursuer",156,167]]},"1:7":{"text":"Jerusalem remembered in the days of her affliction and of her miseries all her pleasant things that she had in the days of old, when her people fell into the hand of the enemy, and none did help her: the adversaries saw her, and did mock at her sabbaths.","words":[["H3389","Jerusalem",0,9],["H2142","remembered",10,20],["H3117","in the days",21,32],["H6040","of her affliction",33,50],["H4788","and of her miseries",51,70],["H4262","all her pleasant things",71,94],["H3117","that she had in the days",95,119],["H6924","of old",120,126],["H5971","when her people",128,143],["H5307","fell",144,148],["H3027","into the hand",149,162],["H6862","of the enemy",163,175],["H5826","and none did help",177,194],["H6862","her: the adversaries",195,215],["H7200","saw",216,219],["H7832","her, and did mock",220,237],["H4868","at her sabbaths",238,253]]},"1:8":{"text":"Jerusalem hath grievously sinned; therefore she is removed: all that honoured her despise her, because they have seen her nakedness: yea, she sigheth, and turneth backward.","words":[["H3389","Jerusalem",0,9],["H2399","hath grievously",10,25],["H2398","sinned",26,32],["H5206","therefore she is removed",34,58],["H3513","all that honoured",60,77],["H2107","her despise",78,89],["H7200","her, because they have seen",90,117],["H6172","her nakedness",118,131],["H0584","yea, she sigheth",133,149],["H7725","and turneth",151,162],["H0268","backward",163,171]]},"1:9":{"text":"Her filthiness is in her skirts; she remembereth not her last end; therefore she came down wonderfully: she had no comforter. O LORD, behold my affliction: for the enemy hath magnified himself.","words":[["H2932","Her filthiness",0,14],["H7757","is in her skirts",15,31],["H2142","she remembereth",33,48],["H0319","not her last end",49,65],["H3381","therefore she came down",67,90],["H6382","wonderfully",91,102],["H5162","she had no comforter",104,124],["H3068","O LORD",126,132],["H7200","behold",134,140],["H6040","my affliction",141,154],["H0341","for the enemy",156,169],["H1431","hath magnified",170,184]]},"1:10":{"text":"The adversary hath spread out his hand upon all her pleasant things: for she hath seen that the heathen entered into her sanctuary, whom thou didst command that they should not enter into thy congregation.","words":[["H6862","The adversary",0,13],["H6566","hath spread out",14,29],["H3027","his hand",30,38],["H4261","upon all her pleasant things",39,67],["H7200","for she hath seen",69,86],["H1471","that the heathen",87,103],["H0935","entered",104,111],["H4720","into her sanctuary",112,130],["H6680","whom thou didst command",132,155],["H0935","that they should not enter",156,182],["H6951","into thy congregation",183,204]]},"1:11":{"text":"All her people sigh, they seek bread; they have given their pleasant things for meat to relieve the soul: see, O LORD, and consider; for I am become vile.","words":[["H5971","All her people",0,14],["H0584","sigh",15,19],["H1245","they seek",21,30],["H3899","bread",31,36],["H5414","they have given",38,53],["H4261","their pleasant things",54,75],["H4262","their pleasant things",54,75],["H0400","for meat",76,84],["H7725","to relieve",85,95],["H5315","the soul",96,104],["H7200","see",106,109],["H3068","O LORD",111,117],["H5027","and consider",119,131],["H2151","for I am become vile",133,153]]},"1:12":{"text":"Is it nothing to you, all ye that pass by? behold, and see if there be any sorrow like unto my sorrow, which is done unto me, wherewith the LORD hath afflicted me in the day of his fierce anger.","words":[["H5674","Is it nothing to you, all ye that pass",0,38],["H1870","by",39,41],["H5027","behold",43,49],["H7200","and see",51,58],["H3426","if there be",59,70],["H4341","any sorrow",71,81],["H4341","like unto my sorrow",82,101],["H5953","which is done",103,116],["H3068","unto me, wherewith the LORD",117,144],["H3013","hath afflicted",145,159],["H3117","me in the day",160,173],["H2740","of his fierce",174,187],["H0639","anger",188,193]]},"1:13":{"text":"From above hath he sent fire into my bones, and it prevaileth against them: he hath spread a net for my feet, he hath turned me back: he hath made me desolate and faint all the day.","words":[["H4791","From above",0,10],["H7971","hath he sent",11,23],["H0784","fire",24,28],["H6106","into my bones",29,42],["H7287","and it prevaileth",44,61],["H6566","against them: he hath spread",62,90],["H7568","a net",91,96],["H7272","for my feet",97,108],["H7725","he hath turned",110,124],["H0268","me back",125,132],["H5414","he hath made",134,146],["H8074","me desolate",147,158],["H1739","and faint",159,168],["H3117","all the day",169,180]]},"1:14":{"text":"The yoke of my transgressions is bound by his hand: they are wreathed, and come up upon my neck: he hath made my strength to fall, the Lord hath delivered me into their hands, from whom I am not able to rise up.","words":[["H5923","The yoke",0,8],["H6588","of my transgressions",9,29],["H8244","is bound",30,38],["H3027","by his hand",39,50],["H8276","they are wreathed",52,69],["H5927","and come up",71,82],["H6677","upon my neck",83,95],["H3581","he hath made my strength",97,121],["H3782","to fall",122,129],["H0136","the Lord",131,139],["H5414","hath delivered",140,154],["H3027","me into their hands",155,174],["H3201","from whom I am not able",176,199],["H6965","to rise up",200,210]]},"1:15":{"text":"The Lord hath trodden under foot all my mighty men in the midst of me: he hath called an assembly against me to crush my young men: the Lord hath trodden the virgin, the daughter of Judah, as in a winepress.","words":[["H0136","The Lord",0,8],["H5541","hath trodden under foot",9,32],["H0047","all my mighty",33,46],["H7130","men in the midst",47,63],["H7121","of me: he hath called",64,85],["H4150","an assembly",86,97],["H7665","against me to crush",98,117],["H0970","my young men",118,130],["H0136","the Lord",132,140],["H1869","hath trodden",141,153],["H1330","the virgin",154,164],["H1323","the daughter",166,178],["H3063","of Judah",179,187],["H1660","as in a winepress",189,206]]},"1:16":{"text":"For these things I weep; mine eye, mine eye runneth down with water, because the comforter that should relieve my soul is far from me: my children are desolate, because the enemy prevailed.","words":[["H1058","For these things I weep",0,23],["H5869","mine eye",25,33],["H5869","mine eye",35,43],["H3381","runneth down",44,56],["H4325","with water",57,67],["H5162","because the comforter",69,90],["H7725","that should relieve",91,110],["H5315","my soul",111,118],["H7368","is far",119,125],["H1121","from me: my children",126,146],["H8074","are desolate",147,159],["H0341","because the enemy",161,178],["H1396","prevailed",179,188]]},"1:17":{"text":"Zion spreadeth forth her hands, and there is none to comfort her: the LORD hath commanded concerning Jacob, that his adversaries should be round about him: Jerusalem is as a menstruous woman among them.","words":[["H6726","Zion",0,4],["H6566","spreadeth forth",5,20],["H3027","her hands",21,30],["H5162","and there is none to comfort",32,60],["H3068","her: the LORD",61,74],["H6680","hath commanded",75,89],["H3290","concerning Jacob",90,106],["H6862","that his adversaries",108,128],["H5439","should be round about",129,150],["H3389","him: Jerusalem",151,165],["H5079","is as a menstruous woman",166,190]]},"1:18":{"text":"The LORD is righteous; for I have rebelled against his commandment: hear, I pray you, all people, and behold my sorrow: my virgins and my young men are gone into captivity.","words":[["H3068","The LORD",0,8],["H6662","is righteous",9,21],["H4784","for I have rebelled",23,42],["H6310","against his commandment",43,66],["H8085","hear",68,72],["H5971","I pray you, all people",74,96],["H7200","and behold",98,108],["H4341","my sorrow",109,118],["H1330","my virgins",120,130],["H0970","and my young men",131,147],["H1980","are gone",148,156],["H7628","into captivity",157,171]]},"1:19":{"text":"I called for my lovers, but they deceived me: my priests and mine elders gave up the ghost in the city, while they sought their meat to relieve their souls.","words":[["H7121","I called",0,8],["H0157","for my lovers",9,22],["H7411","but they deceived",24,41],["H3548","me: my priests",42,56],["H2205","and mine elders",57,72],["H1478","gave up the ghost",73,90],["H5892","in the city",91,102],["H1245","while they sought",104,121],["H0400","their meat",122,132],["H7725","to relieve",133,143],["H5315","their souls",144,155]]},"1:20":{"text":"Behold, O LORD; for I am in distress: my bowels are troubled; mine heart is turned within me; for I have grievously rebelled: abroad the sword bereaveth, at home there is as death.","words":[["H7200","Behold",0,6],["H3068","O LORD",8,14],["H6887","for I am in distress",16,36],["H4578","my bowels",38,47],["H2560","are troubled",48,60],["H3820","mine heart",62,72],["H2015","is turned",73,82],["H7130","within",83,89],["H4784","me; for I have grievously",90,115],["H4784","rebelled",116,124],["H2351","abroad",126,132],["H2719","the sword",133,142],["H7921","bereaveth",143,152],["H1004","at home",154,161],["H4194","there is as death",162,179]]},"1:21":{"text":"They have heard that I sigh: there is none to comfort me: all mine enemies have heard of my trouble; they are glad that thou hast done it: thou wilt bring the day that thou hast called, and they shall be like unto me.","words":[["H8085","They have heard",0,15],["H0584","that I sigh",16,27],["H5162","there is none to comfort",29,53],["H0341","me: all mine enemies",54,74],["H8085","have heard",75,85],["H7451","of my trouble",86,99],["H7797","they are glad",101,114],["H6213","that thou hast done",115,134],["H0935","it: thou wilt bring",135,154],["H3117","the day",155,162],["H7121","that thou hast called",163,184],["H3644","and they shall be like",186,208]]},"1:22":{"text":"Let all their wickedness come before thee; and do unto them, as thou hast done unto me for all my transgressions: for my sighs are many, and my heart is faint.","words":[["H7451","Let all their wickedness",0,24],["H0935","come",25,29],["H6440","before",30,36],["H5953","thee; and do",37,49],["H5953","unto them, as thou hast done",50,78],["H6588","unto me for all my transgressions",79,112],["H0585","for my sighs",114,126],["H7227","are many",127,135],["H3820","and my heart",137,149],["H1742","is faint",150,158]]},"2:1":{"text":"How hath the Lord covered the daughter of Zion with a cloud in his anger, and cast down from heaven unto the earth the beauty of Israel, and remembered not his footstool in the day of his anger!","words":[["H0136","How hath the Lord",0,17],["H5743","covered",18,25],["H1323","the daughter",26,38],["H6726","of Zion",39,46],["H5743","with a cloud",47,59],["H0639","in his anger",60,72],["H7993","and cast down",74,87],["H8064","from heaven",88,99],["H0776","unto the earth",100,114],["H8597","the beauty",115,125],["H3478","of Israel",126,135],["H2142","and remembered",137,151],["H1916","not his footstool",152,169],["H7272","not his footstool",152,169],["H3117","in the day",170,180],["H0639","of his anger",181,193]]},"2:2":{"text":"The Lord hath swallowed up all the habitations of Jacob, and hath not pitied: he hath thrown down in his wrath the strong holds of the daughter of Judah; he hath brought them down to the ground: he hath polluted the kingdom and the princes thereof.","words":[["H0136","The Lord",0,8],["H1104","hath swallowed up",9,26],["H4999","all the habitations",27,46],["H3290","of Jacob",47,55],["H2550","and hath not pitied",57,76],["H2040","he hath thrown down",78,97],["H5678","in his wrath",98,110],["H4013","the strong holds",111,127],["H1323","of the daughter",128,143],["H3063","of Judah",144,152],["H5060","he hath brought them down",154,179],["H0776","to the ground",180,193],["H2490","he hath polluted",195,211],["H4467","the kingdom",212,223],["H8269","and the princes",224,239]]},"2:3":{"text":"He hath cut off in his fierce anger all the horn of Israel: he hath drawn back his right hand from before the enemy, and he burned against Jacob like a flaming fire, which devoureth round about.","words":[["H1438","He hath cut off",0,15],["H2750","in his fierce",16,29],["H0639","anger",30,35],["H7161","all the horn",36,48],["H3478","of Israel",49,58],["H7725","he hath drawn",60,73],["H0268","back",74,78],["H3225","his right hand",79,93],["H6440","from before",94,105],["H0341","the enemy",106,115],["H1197","and he burned",117,130],["H3290","against Jacob",131,144],["H3852","like a flaming",145,159],["H0784","fire",160,164],["H0398","which devoureth",166,181],["H5439","round about",182,193]]},"2:4":{"text":"He hath bent his bow like an enemy: he stood with his right hand as an adversary, and slew all that were pleasant to the eye in the tabernacle of the daughter of Zion: he poured out his fury like fire.","words":[["H1869","He hath bent",0,12],["H7198","his bow",13,20],["H0341","like an enemy",21,34],["H5324","he stood",36,44],["H3225","with his right hand",45,64],["H6862","as an adversary",65,80],["H2026","and slew",82,90],["H4261","all that were pleasant",91,113],["H5869","to the eye",114,124],["H0168","in the tabernacle",125,142],["H1323","of the daughter",143,158],["H6726","of Zion",159,166],["H8210","he poured out",168,181],["H2534","his fury",182,190],["H0784","like fire",191,200]]},"2:5":{"text":"The Lord was as an enemy: he hath swallowed up Israel, he hath swallowed up all her palaces: he hath destroyed his strong holds, and hath increased in the daughter of Judah mourning and lamentation.","words":[["H0136","The Lord",0,8],["H0341","was as an enemy",9,24],["H1104","he hath swallowed up",26,46],["H3478","Israel",47,53],["H1104","he hath swallowed up",55,75],["H0759","all her palaces",76,91],["H7843","he hath destroyed",93,110],["H4013","his strong holds",111,127],["H7235","and hath increased",129,147],["H1323","in the daughter",148,163],["H3063","of Judah",164,172],["H8386","mourning",173,181],["H0592","and lamentation",182,197]]},"2:6":{"text":"And he hath violently taken away his tabernacle, as if it were of a garden: he hath destroyed his places of the assembly: the LORD hath caused the solemn feasts and sabbaths to be forgotten in Zion, and hath despised in the indignation of his anger the king and the priest.","words":[["H2554","And he hath violently taken away",0,32],["H7900","his tabernacle",33,47],["H1588","as if it were of a garden",49,74],["H7843","he hath destroyed",76,93],["H4150","his places of the assembly",94,120],["H3068","the LORD",122,130],["H4150","hath caused the solemn feasts",131,160],["H7676","and sabbaths",161,173],["H7911","to be forgotten",174,189],["H6726","in Zion",190,197],["H5006","and hath despised",199,216],["H2195","in the indignation",217,235],["H0639","of his anger",236,248],["H4428","the king",249,257],["H3548","and the priest",258,272]]},"2:7":{"text":"The Lord hath cast off his altar, he hath abhorred his sanctuary, he hath given up into the hand of the enemy the walls of her palaces; they have made a noise in the house of the LORD, as in the day of a solemn feast.","words":[["H0136","The Lord",0,8],["H2186","hath cast off",9,22],["H4196","his altar",23,32],["H5010","he hath abhorred",34,50],["H4720","his sanctuary",51,64],["H5462","he hath given up",66,82],["H3027","into the hand",83,96],["H0341","of the enemy",97,109],["H2346","the walls",110,119],["H0759","of her palaces",120,134],["H5414","they have made",136,150],["H6963","a noise",151,158],["H1004","in the house",159,171],["H3068","of the LORD",172,183],["H3117","as in the day",185,198],["H4150","of a solemn feast",199,216]]},"2:8":{"text":"The LORD hath purposed to destroy the wall of the daughter of Zion: he hath stretched out a line, he hath not withdrawn his hand from destroying: therefore he made the rampart and the wall to lament; they languished together.","words":[["H3068","The LORD",0,8],["H2803","hath purposed",9,22],["H7843","to destroy",23,33],["H2346","the wall",34,42],["H1323","of the daughter",43,58],["H6726","of Zion",59,66],["H5186","he hath stretched out",68,89],["H6957","a line",90,96],["H7725","he hath not withdrawn",98,119],["H3027","his hand",120,128],["H1104","from destroying",129,144],["H2426","therefore he made the rampart",146,175],["H2346","and the wall",176,188],["H0056","to lament",189,198],["H0535","they languished",200,215],["H3162","together",216,224]]},"2:9":{"text":"Her gates are sunk into the ground; he hath destroyed and broken her bars: her king and her princes are among the Gentiles: the law is no more; her prophets also find no vision from the LORD.","words":[["H8179","Her gates",0,9],["H2883","are sunk",10,18],["H0776","into the ground",19,34],["H0006","he hath destroyed",36,53],["H7665","and broken",54,64],["H1280","her bars",65,73],["H4428","her king",75,83],["H8269","and her princes",84,99],["H1471","are among the Gentiles",100,122],["H8451","the law",124,131],["H5030","is no more; her prophets",132,156],["H4672","also find",157,166],["H2377","no vision",167,176],["H3068","from the LORD",177,190]]},"2:10":{"text":"The elders of the daughter of Zion sit upon the ground, and keep silence: they have cast up dust upon their heads; they have girded themselves with sackcloth: the virgins of Jerusalem hang down their heads to the ground.","words":[["H2205","The elders",0,10],["H1323","of the daughter",11,26],["H6726","of Zion",27,34],["H3427","sit",35,38],["H0776","upon the ground",39,54],["H1826","and keep silence",56,72],["H5927","they have cast up",74,91],["H6083","dust",92,96],["H7218","upon their heads",97,113],["H2296","they have girded",115,131],["H8242","themselves with sackcloth",132,157],["H1330","the virgins",159,170],["H3389","of Jerusalem",171,183],["H3381","hang down",184,193],["H7218","their heads",194,205],["H0776","to the ground",206,219]]},"2:11":{"text":"Mine eyes do fail with tears, my bowels are troubled, my liver is poured upon the earth, for the destruction of the daughter of my people; because the children and the sucklings swoon in the streets of the city.","words":[["H5869","Mine eyes",0,9],["H3615","do fail",10,17],["H1832","with tears",18,28],["H4578","my bowels",30,39],["H2560","are troubled",40,52],["H3516","my liver",54,62],["H8210","is poured",63,72],["H0776","upon the earth",73,87],["H7667","for the destruction",89,108],["H1323","of the daughter",109,124],["H5971","of my people",125,137],["H5768","because the children",139,159],["H3243","and the sucklings",160,177],["H5848","swoon",178,183],["H7339","in the streets",184,198],["H7151","of the city",199,210]]},"2:12":{"text":"They say to their mothers, Where is corn and wine? when they swooned as the wounded in the streets of the city, when their soul was poured out into their mothers' bosom.","words":[["H0559","They say",0,8],["H0517","to their mothers",9,25],["H1715","Where is corn",27,40],["H3196","and wine",41,49],["H5848","when they swooned",51,68],["H2491","as the wounded",69,83],["H7339","in the streets",84,98],["H5892","of the city",99,110],["H5315","when their soul",112,127],["H8210","was poured out",128,142],["H0517","into their mothers'",143,162],["H2436","bosom",163,168]]},"2:13":{"text":"What thing shall I take to witness for thee? what thing shall I liken to thee, O daughter of Jerusalem? what shall I equal to thee, that I may comfort thee, O virgin daughter of Zion? for thy breach is great like the sea: who can heal thee?","words":[["H5749","What thing shall I take to witness",0,34],["H5749","What thing shall I take to witness",0,34],["H4100","for thee? what thing",35,55],["H1819","shall I liken",56,69],["H1323","to thee, O daughter",70,89],["H3389","of Jerusalem",90,102],["H7737","what shall I equal",104,122],["H5162","to thee, that I may comfort",123,150],["H1330","thee, O virgin",151,165],["H1323","daughter",166,174],["H6726","of Zion",175,182],["H7667","for thy breach",184,198],["H1419","is great",199,207],["H3220","like the sea",208,220],["H7495","who can heal",222,234]]},"2:14":{"text":"Thy prophets have seen vain and foolish things for thee: and they have not discovered thine iniquity, to turn away thy captivity; but have seen for thee false burdens and causes of banishment.","words":[["H5030","Thy prophets",0,12],["H2372","have seen",13,22],["H7723","vain",23,27],["H8602","and foolish things",28,46],["H1540","for thee: and they have not discovered",47,85],["H5771","thine iniquity",86,100],["H7725","to turn away",102,114],["H7622","thy captivity",115,128],["H7622","thy captivity",115,128],["H2372","but have seen",130,143],["H7723","for thee false",144,158],["H4864","burdens",159,166],["H4065","and causes of banishment",167,191]]},"2:15":{"text":"All that pass by clap their hands at thee; they hiss and wag their head at the daughter of Jerusalem, saying, Is this the city that men call The perfection of beauty, The joy of the whole earth?","words":[["H5674","All that pass",0,13],["H5606","by clap",14,21],["H3709","their hands",22,33],["H1870","at thee",34,41],["H8319","they hiss",43,52],["H5128","and wag",53,60],["H7218","their head",61,71],["H1323","at the daughter",72,87],["H3389","of Jerusalem",88,100],["H5892","saying, Is this the city",102,126],["H0559","that men call",127,140],["H3632","The perfection",141,155],["H3308","of beauty",156,165],["H4885","The joy",167,174],["H0776","of the whole earth",175,193]]},"2:16":{"text":"All thine enemies have opened their mouth against thee: they hiss and gnash the teeth: they say, We have swallowed her up: certainly this is the day that we looked for; we have found, we have seen it.","words":[["H0341","All thine enemies",0,17],["H6475","have opened",18,29],["H6310","their mouth",30,41],["H8319","against thee: they hiss",42,65],["H2786","and gnash",66,75],["H8127","the teeth",76,85],["H0559","they say",87,95],["H1104","We have swallowed her up",97,121],["H0389","certainly",123,132],["H3117","this is the day",133,148],["H6960","that we looked for",149,167],["H4672","we have found",169,182],["H7200","we have seen",184,196]]},"2:17":{"text":"The LORD hath done that which he had devised; he hath fulfilled his word that he had commanded in the days of old: he hath thrown down, and hath not pitied: and he hath caused thine enemy to rejoice over thee, he hath set up the horn of thine adversaries.","words":[["H3068","The LORD",0,8],["H6213","hath done",9,18],["H2161","that which he had devised",19,44],["H1214","he hath fulfilled",46,63],["H0565","his word",64,72],["H6680","that he had commanded",73,94],["H3117","in the days",95,106],["H6924","of old",107,113],["H2040","he hath thrown down",115,134],["H2550","and hath not pitied",136,155],["H0341","and he hath caused thine enemy",157,187],["H8055","to rejoice",188,198],["H7311","over thee, he hath set up",199,224],["H7161","the horn",225,233],["H6862","of thine adversaries",234,254]]},"2:18":{"text":"Their heart cried unto the Lord, O wall of the daughter of Zion, let tears run down like a river day and night: give thyself no rest; let not the apple of thine eye cease.","words":[["H3820","Their heart",0,11],["H6817","cried",12,17],["H0136","unto the Lord",18,31],["H2346","O wall",33,39],["H1323","of the daughter",40,55],["H6726","of Zion",56,63],["H1832","let tears",65,74],["H3381","run down",75,83],["H5158","like a river",84,96],["H3119","day",97,100],["H3915","and night",101,110],["H5414","give",112,116],["H6314","thyself no rest",117,132],["H1323","let not the apple",134,151],["H5869","of thine eye",152,164],["H1826","cease",165,170]]},"2:19":{"text":"Arise, cry out in the night: in the beginning of the watches pour out thine heart like water before the face of the Lord: lift up thy hands toward him for the life of thy young children, that faint for hunger in the top of every street.","words":[["H6965","Arise",0,5],["H7442","cry out",7,14],["H3915","in the night",15,27],["H7218","in the beginning",29,45],["H0821","of the watches",46,60],["H8210","pour out",61,69],["H3820","thine heart",70,81],["H4325","like water",82,92],["H5227","before",93,99],["H6440","the face",100,108],["H0136","of the Lord",109,120],["H5375","lift up",122,129],["H3709","thy hands",130,139],["H5315","toward him for the life",140,163],["H5768","of thy young children",164,185],["H5848","that faint",187,197],["H7458","for hunger",198,208],["H7218","in the top",209,219],["H2351","of every street",220,235]]},"2:20":{"text":"Behold, O LORD, and consider to whom thou hast done this. Shall the women eat their fruit, and children of a span long? shall the priest and the prophet be slain in the sanctuary of the Lord?","words":[["H7200","Behold",0,6],["H3068","O LORD",8,14],["H5027","and consider",16,28],["H5953","to whom thou hast done",29,51],["H3541","this",52,56],["H0802","Shall the women",58,73],["H0398","eat",74,77],["H6529","their fruit",78,89],["H5768","and children",91,103],["H2949","of a span long",104,118],["H3548","shall the priest",120,136],["H5030","and the prophet",137,152],["H2026","be slain",153,161],["H4720","in the sanctuary",162,178],["H0136","of the Lord",179,190]]},"2:21":{"text":"The young and the old lie on the ground in the streets: my virgins and my young men are fallen by the sword; thou hast slain them in the day of thine anger; thou hast killed, and not pitied.","words":[["H5288","The young",0,9],["H2205","and the old",10,21],["H7901","lie",22,25],["H0776","on the ground",26,39],["H2351","in the streets",40,54],["H1330","my virgins",56,66],["H0970","and my young men",67,83],["H5307","are fallen",84,94],["H2719","by the sword",95,107],["H2026","thou hast slain",109,124],["H3117","them in the day",125,140],["H0639","of thine anger",141,155],["H2873","thou hast killed",157,173],["H2550","and not pitied",175,189]]},"2:22":{"text":"Thou hast called as in a solemn day my terrors round about, so that in the day of the LORD'S anger none escaped nor remained: those that I have swaddled and brought up hath mine enemy consumed.","words":[["H7121","Thou hast called",0,16],["H4150","as in a solemn",17,31],["H3117","day",32,35],["H4032","my terrors",36,46],["H5439","round about",47,58],["H3117","so that in the day",60,78],["H3068","of the LORD'S",79,92],["H0639","anger",93,98],["H6412","none escaped",99,111],["H8300","nor remained",112,124],["H2946","those that I have swaddled",126,152],["H7235","and brought up",153,167],["H0341","hath mine enemy",168,183],["H3615","consumed",184,192]]},"3:1":{"text":"I am the man that hath seen affliction by the rod of his wrath.","words":[["H1397","I am the man",0,12],["H7200","that hath seen",13,27],["H6040","affliction",28,38],["H7626","by the rod",39,49],["H5678","of his wrath",50,62]]},"3:2":{"text":"He hath led me, and brought me into darkness, but not into light.","words":[["H5090","He hath led",0,11],["H3212","me, and brought",12,27],["H2822","me into darkness",28,44],["H0216","but not into light",46,64]]},"3:3":{"text":"Surely against me is he turned; he turneth his hand against me all the day.","words":[["H7725","Surely against me is he turned",0,30],["H2015","he turneth",32,42],["H3027","his hand",43,51],["H3117","against me all the day",52,74]]},"3:4":{"text":"My flesh and my skin hath he made old; he hath broken my bones.","words":[["H1320","My flesh",0,8],["H5785","and my skin",9,20],["H1086","hath he made old",21,37],["H7665","he hath broken",39,53],["H6106","my bones",54,62]]},"3:5":{"text":"He hath builded against me, and compassed me with gall and travail.","words":[["H1129","He hath builded against",0,23],["H5362","me, and compassed",24,41],["H7219","me with gall",42,54],["H8513","and travail",55,66]]},"3:6":{"text":"He hath set me in dark places, as they that be dead of old.","words":[["H3427","He hath set",0,11],["H4285","me in dark places",12,29],["H4191","as they that be dead",31,51],["H5769","of old",52,58]]},"3:7":{"text":"He hath hedged me about, that I cannot get out: he hath made my chain heavy.","words":[["H1443","He hath hedged",0,14],["H3318","me about, that I cannot get out",15,46],["H5178","he hath made my chain",48,69],["H3513","heavy",70,75]]},"3:8":{"text":"Also when I cry and shout, he shutteth out my prayer.","words":[["H2199","Also when I cry",0,15],["H7768","and shout",16,25],["H5640","he shutteth out",27,42],["H8605","my prayer",43,52]]},"3:9":{"text":"He hath inclosed my ways with hewn stone, he hath made my paths crooked.","words":[["H1443","He hath inclosed",0,16],["H1870","my ways",17,24],["H1496","with hewn stone",25,40],["H5410","he hath made my paths",42,63],["H5753","crooked",64,71]]},"3:10":{"text":"He was unto me as a bear lying in wait, and as a lion in secret places.","words":[["H1677","He was unto me as a bear",0,24],["H0693","lying in wait",25,38],["H0738","and as a lion",40,53],["H4565","in secret places",54,70]]},"3:11":{"text":"He hath turned aside my ways, and pulled me in pieces: he hath made me desolate.","words":[["H5493","He hath turned aside",0,20],["H1870","my ways",21,28],["H6582","and pulled me in pieces",30,53],["H7760","he hath made",55,67],["H8074","me desolate",68,79]]},"3:12":{"text":"He hath bent his bow, and set me as a mark for the arrow.","words":[["H1869","He hath bent",0,12],["H7198","his bow",13,20],["H5324","and set",22,29],["H4307","me as a mark",30,42],["H2671","for the arrow",43,56]]},"3:13":{"text":"He hath caused the arrows of his quiver to enter into my reins.","words":[["H1121","He hath caused the arrows",0,25],["H0827","of his quiver",26,39],["H0935","to enter",40,48],["H3629","into my reins",49,62]]},"3:14":{"text":"I was a derision to all my people; and their song all the day.","words":[["H7814","I was a derision",0,16],["H5971","to all my people",17,33],["H5058","and their song",35,49],["H3117","all the day",50,61]]},"3:15":{"text":"He hath filled me with bitterness, he hath made me drunken with wormwood.","words":[["H7646","He hath filled",0,14],["H4844","me with bitterness",15,33],["H7301","he hath made me drunken",35,58],["H3939","with wormwood",59,72]]},"3:16":{"text":"He hath also broken my teeth with gravel stones, he hath covered me with ashes.","words":[["H1638","He hath also broken",0,19],["H8127","my teeth",20,28],["H2687","with gravel stones",29,47],["H3728","he hath covered",49,64],["H0665","me with ashes",65,78]]},"3:17":{"text":"And thou hast removed my soul far off from peace: I forgat prosperity.","words":[["H2186","And thou hast removed",0,21],["H5315","my soul",22,29],["H2186","far off",30,37],["H7965","from peace",38,48],["H5382","I forgat",50,58],["H2896","prosperity",59,69]]},"3:18":{"text":"And I said, My strength and my hope is perished from the LORD:","words":[["H0559","And I said",0,10],["H5331","My strength",12,23],["H8431","and my hope",24,35],["H0006","is perished",36,47],["H3068","from the LORD",48,61]]},"3:19":{"text":"Remembering mine affliction and my misery, the wormwood and the gall.","words":[["H2142","Remembering",0,11],["H6040","mine affliction",12,27],["H4788","and my misery",28,41],["H3939","the wormwood",43,55],["H7219","and the gall",56,68]]},"3:20":{"text":"My soul hath them still in remembrance, and is humbled in me.","words":[["H5315","My soul",0,7],["H2142","hath them still",8,23],["H2142","in remembrance",24,38],["H7743","and is humbled",40,54]]},"3:21":{"text":"This I recall to my mind, therefore have I hope.","words":[["H7725","This I recall",0,13],["H3820","to my mind",14,24],["H3176","therefore have I hope",26,47]]},"3:22":{"text":"It is of the LORD'S mercies that we are not consumed, because his compassions fail not.","words":[["H3068","It is of the LORD'S",0,19],["H2617","mercies",20,27],["H8552","that we are not consumed",28,52],["H7356","because his compassions",54,77],["H3615","fail",78,82]]},"3:23":{"text":"They are new every morning: great is thy faithfulness.","words":[["H2319","They are new",0,12],["H1242","every morning",13,26],["H7227","great",28,33],["H0530","is thy faithfulness",34,53]]},"3:24":{"text":"The LORD is my portion, saith my soul; therefore will I hope in him.","words":[["H3068","The LORD",0,8],["H2506","is my portion",9,22],["H0559","saith",24,29],["H5315","my soul",30,37],["H3176","therefore will I hope",39,60]]},"3:25":{"text":"The LORD is good unto them that wait for him, to the soul that seeketh him.","words":[["H3068","The LORD",0,8],["H2896","is good",9,16],["H6960","unto them that wait",17,36],["H5315","for him, to the soul",37,57],["H1875","that seeketh",58,70]]},"3:26":{"text":"It is good that a man should both hope and quietly wait for the salvation of the LORD.","words":[["H2896","It is good",0,10],["H3175","that a man should both hope",11,38],["H2342","that a man should both hope",11,38],["H1748","and quietly wait",39,55],["H8668","for the salvation",56,73],["H3068","of the LORD",74,85]]},"3:27":{"text":"It is good for a man that he bear the yoke in his youth.","words":[["H2896","It is good",0,10],["H1397","for a man",11,20],["H5375","that he bear",21,33],["H5923","the yoke",34,42],["H5271","in his youth",43,55]]},"3:28":{"text":"He sitteth alone and keepeth silence, because he hath borne it upon him.","words":[["H3427","He sitteth",0,10],["H0910","alone",11,16],["H1826","and keepeth silence",17,36],["H5190","because he hath borne",38,59]]},"3:29":{"text":"He putteth his mouth in the dust; if so be there may be hope.","words":[["H5414","He putteth",0,10],["H6310","his mouth",11,20],["H6083","in the dust",21,32],["H3426","if so be there may be",34,55],["H8615","hope",56,60]]},"3:30":{"text":"He giveth his cheek to him that smiteth him: he is filled full with reproach.","words":[["H5414","He giveth",0,9],["H3895","his cheek",10,19],["H5221","to him that smiteth",20,39],["H7646","him: he is filled full",40,62],["H2781","with reproach",63,76]]},"3:31":{"text":"For the Lord will not cast off for ever:","words":[["H0136","For the Lord",0,12],["H2186","will not cast off",13,30],["H5769","for ever",31,39]]},"3:32":{"text":"But though he cause grief, yet will he have compassion according to the multitude of his mercies.","words":[["H3013","But though he cause grief",0,25],["H7355","yet will he have compassion",27,54],["H7230","according to the multitude",55,81],["H2617","of his mercies",82,96]]},"3:33":{"text":"For he doth not afflict willingly nor grieve the children of men.","words":[["H6031","For he doth not afflict",0,23],["H3820","willingly",24,33],["H3013","nor grieve",34,44],["H1121","the children",45,57],["H0376","of men",58,64]]},"3:34":{"text":"To crush under his feet all the prisoners of the earth,","words":[["H1792","To crush",0,8],["H7272","under his feet",9,23],["H0615","all the prisoners",24,41],["H0776","of the earth",42,54]]},"3:35":{"text":"To turn aside the right of a man before the face of the most High,","words":[["H5186","To turn aside",0,13],["H4941","the right",14,23],["H1397","of a man",24,32],["H6440","before the face",33,48],["H5945","of the most High",49,65]]},"3:36":{"text":"To subvert a man in his cause, the Lord approveth not.","words":[["H5791","To subvert",0,10],["H0120","a man",11,16],["H7379","in his cause",17,29],["H0136","the Lord",31,39],["H7200","approveth",40,49]]},"3:37":{"text":"Who is he that saith, and it cometh to pass, when the Lord commandeth it not?","words":[["H0559","Who is he that saith",0,20],["H0136","and it cometh to pass, when the Lord",22,58],["H6680","commandeth",59,69]]},"3:38":{"text":"Out of the mouth of the most High proceedeth not evil and good?","words":[["H6310","Out of the mouth",0,16],["H5945","of the most High",17,33],["H3318","proceedeth",34,44],["H7451","not evil",45,53],["H2896","and good",54,62]]},"3:39":{"text":"Wherefore doth a living man complain, a man for the punishment of his sins?","words":[["H2416","Wherefore doth a living",0,23],["H0120","man",24,27],["H0596","complain",28,36],["H1397","a man",38,43],["H2399","for the punishment of his sins",44,74]]},"3:40":{"text":"Let us search and try our ways, and turn again to the LORD.","words":[["H2664","Let us search",0,13],["H2713","and try",14,21],["H1870","our ways",22,30],["H7725","and turn again",32,46],["H3068","to the LORD",47,58]]},"3:41":{"text":"Let us lift up our heart with our hands unto God in the heavens.","words":[["H5375","Let us lift up",0,14],["H3824","our heart",15,24],["H3709","with our hands",25,39],["H0410","unto God",40,48],["H8064","in the heavens",49,63]]},"3:42":{"text":"We have transgressed and have rebelled: thou hast not pardoned.","words":[["H5168","We",0,2],["H6586","have transgressed",3,20],["H4784","and have rebelled",21,38],["H5545","thou hast not pardoned",40,62]]},"3:43":{"text":"Thou hast covered with anger, and persecuted us: thou hast slain, thou hast not pitied.","words":[["H5526","Thou hast covered",0,17],["H0639","with anger",18,28],["H7291","and persecuted",30,44],["H2026","us: thou hast slain",45,64],["H2550","thou hast not pitied",66,86]]},"3:44":{"text":"Thou hast covered thyself with a cloud, that our prayer should not pass through.","words":[["H5526","Thou hast covered",0,17],["H6051","thyself with a cloud",18,38],["H8605","that our prayer",40,55],["H5674","should not pass through",56,79]]},"3:45":{"text":"Thou hast made us as the offscouring and refuse in the midst of the people.","words":[["H7760","Thou hast made",0,14],["H5501","us as the offscouring",15,36],["H3973","and refuse",37,47],["H7130","in the midst",48,60],["H5971","of the people",61,74]]},"3:46":{"text":"All our enemies have opened their mouths against us.","words":[["H0341","All our enemies",0,15],["H6475","have opened",16,27],["H6310","their mouths",28,40]]},"3:47":{"text":"Fear and a snare is come upon us, desolation and destruction.","words":[["H6343","Fear",0,4],["H6354","and a snare",5,16],["H7612","is come upon us, desolation",17,44],["H7667","and destruction",45,60]]},"3:48":{"text":"Mine eye runneth down with rivers of water for the destruction of the daughter of my people.","words":[["H5869","Mine eye",0,8],["H3381","runneth down",9,21],["H6388","with rivers",22,33],["H4325","of water",34,42],["H7667","for the destruction",43,62],["H1323","of the daughter",63,78],["H5971","of my people",79,91]]},"3:49":{"text":"Mine eye trickleth down, and ceaseth not, without any intermission,","words":[["H5869","Mine eye",0,8],["H5064","trickleth down",9,23],["H1820","and ceaseth",25,36],["H2014","not, without any intermission",37,66]]},"3:50":{"text":"Till the LORD look down, and behold from heaven.","words":[["H3068","Till the LORD",0,13],["H8259","look down",14,23],["H7200","and behold",25,35],["H8064","from heaven",36,47]]},"3:51":{"text":"Mine eye affecteth mine heart because of all the daughters of my city.","words":[["H5869","Mine eye",0,8],["H5953","affecteth",9,18],["H5315","mine heart",19,29],["H1323","because of all the daughters",30,58],["H5892","of my city",59,69]]},"3:52":{"text":"Mine enemies chased me sore, like a bird, without cause.","words":[["H0341","Mine enemies",0,12],["H6679","chased",13,19],["H6679","me sore",20,27],["H6833","like a bird",29,40],["H2600","without cause",42,55]]},"3:53":{"text":"They have cut off my life in the dungeon, and cast a stone upon me.","words":[["H6789","They have cut off",0,17],["H2416","my life",18,25],["H0953","in the dungeon",26,40],["H3034","and cast",42,50],["H0068","a stone",51,58]]},"3:54":{"text":"Waters flowed over mine head; then I said, I am cut off.","words":[["H4325","Waters",0,6],["H6687","flowed over",7,18],["H7218","mine head",19,28],["H0559","then I said",30,41],["H1504","I am cut off",43,55]]},"3:55":{"text":"I called upon thy name, O LORD, out of the low dungeon.","words":[["H7121","I called",0,8],["H8034","upon thy name",9,22],["H3068","O LORD",24,30],["H8482","out of the low",32,46],["H0953","dungeon",47,54]]},"3:56":{"text":"Thou hast heard my voice: hide not thine ear at my breathing, at my cry.","words":[["H8085","Thou hast heard",0,15],["H6963","my voice",16,24],["H5956","hide",26,30],["H0241","not thine ear",31,44],["H7309","at my breathing",45,60],["H7775","at my cry",62,71]]},"3:57":{"text":"Thou drewest near in the day that I called upon thee: thou saidst, Fear not.","words":[["H7126","Thou drewest near",0,17],["H3117","in the day",18,28],["H7121","that I called",29,42],["H0559","upon thee: thou saidst",43,65],["H3372","Fear",67,71]]},"3:58":{"text":"O Lord, thou hast pleaded the causes of my soul; thou hast redeemed my life.","words":[["H0136","O Lord",0,6],["H7378","thou hast pleaded",8,25],["H7379","the causes",26,36],["H5315","of my soul",37,47],["H1350","thou hast redeemed",49,67],["H2416","my life",68,75]]},"3:59":{"text":"O LORD, thou hast seen my wrong: judge thou my cause.","words":[["H3068","O LORD",0,6],["H7200","thou hast seen",8,22],["H5792","my wrong",23,31],["H8199","judge",33,38],["H4941","thou my cause",39,52]]},"3:60":{"text":"Thou hast seen all their vengeance and all their imaginations against me.","words":[["H7200","Thou hast seen",0,14],["H5360","all their vengeance",15,34],["H4284","and all their imaginations",35,61]]},"3:61":{"text":"Thou hast heard their reproach, O LORD, and all their imaginations against me;","words":[["H8085","Thou hast heard",0,15],["H2781","their reproach",16,30],["H3068","O LORD",32,38],["H4284","and all their imaginations",40,66]]},"3:62":{"text":"The lips of those that rose up against me, and their device against me all the day.","words":[["H8193","The lips",0,8],["H6965","of those that rose up",9,30],["H1902","against me, and their device",31,59],["H3117","against me all the day",60,82]]},"3:63":{"text":"Behold their sitting down, and their rising up; I am their musick.","words":[["H5027","Behold",0,6],["H3427","their sitting down",7,25],["H7012","and their rising up",27,46],["H4485","I am their musick",48,65]]},"3:64":{"text":"Render unto them a recompence, O LORD, according to the work of their hands.","words":[["H7725","Render",0,6],["H1576","unto them a recompence",7,29],["H3068","O LORD",31,37],["H4639","according to the work",39,60],["H3027","of their hands",61,75]]},"3:65":{"text":"Give them sorrow of heart, thy curse unto them.","words":[["H5414","Give",0,4],["H4044","them sorrow",5,16],["H3820","of heart",17,25],["H8381","thy curse",27,36]]},"3:66":{"text":"Persecute and destroy them in anger from under the heavens of the LORD.","words":[["H7291","Persecute",0,9],["H8045","and destroy",10,21],["H0639","them in anger",22,35],["H8064","from under the heavens",36,58],["H3068","of the LORD",59,70]]},"4:1":{"text":"How is the gold become dim! how is the most fine gold changed! the stones of the sanctuary are poured out in the top of every street.","words":[["H2091","How is the gold",0,15],["H6004","become dim",16,26],["H2896","how is the most",28,43],["H3800","fine gold",44,53],["H8132","changed",54,61],["H0068","the stones",63,73],["H6944","of the sanctuary",74,90],["H8210","are poured out",91,105],["H7218","in the top",106,116],["H2351","of every street",117,132]]},"4:2":{"text":"The precious sons of Zion, comparable to fine gold, how are they esteemed as earthen pitchers, the work of the hands of the potter!","words":[["H3368","The precious",0,12],["H1121","sons",13,17],["H6726","of Zion",18,25],["H5537","comparable",27,37],["H6337","to fine gold",38,50],["H2803","how are they esteemed",52,73],["H2789","as earthen",74,84],["H5035","pitchers",85,93],["H4639","the work",95,103],["H3027","of the hands",104,116],["H3335","of the potter",117,130]]},"4:3":{"text":"Even the sea monsters draw out the breast, they give suck to their young ones: the daughter of my people is become cruel, like the ostriches in the wilderness.","words":[["H8577","Even the sea monsters",0,21],["H2502","draw out",22,30],["H7699","the breast",31,41],["H3243","they give suck",43,57],["H1482","to their young ones",58,77],["H1323","the daughter",79,91],["H5971","of my people",92,104],["H0393","is become cruel",105,120],["H3283","like the ostriches",122,140],["H4057","in the wilderness",141,158]]},"4:4":{"text":"The tongue of the sucking child cleaveth to the roof of his mouth for thirst: the young children ask bread, and no man breaketh it unto them.","words":[["H3956","The tongue",0,10],["H3243","of the sucking child",11,31],["H1692","cleaveth",32,40],["H2441","to the roof of his mouth",41,65],["H6772","for thirst",66,76],["H5768","the young children",78,96],["H7592","ask",97,100],["H3899","bread",101,106],["H6566","and no man breaketh",108,127]]},"4:5":{"text":"They that did feed delicately are desolate in the streets: they that were brought up in scarlet embrace dunghills.","words":[["H0398","They that did feed",0,18],["H4574","delicately",19,29],["H8074","are desolate",30,42],["H2351","in the streets",43,57],["H0539","they that were brought up",59,84],["H8438","in scarlet",85,95],["H2263","embrace",96,103],["H0830","dunghills",104,113]]},"4:6":{"text":"For the punishment of the iniquity of the daughter of my people is greater than the punishment of the sin of Sodom, that was overthrown as in a moment, and no hands stayed on her.","words":[["H5771","For the punishment of the iniquity",0,34],["H1323","of the daughter",35,50],["H5971","of my people",51,63],["H1431","is greater",64,74],["H2403","than the punishment",75,94],["H5467","of the sin of Sodom",95,114],["H2015","that was overthrown",116,135],["H7281","as in a moment",136,150],["H3027","and no hands",152,164],["H2342","stayed",165,171]]},"4:7":{"text":"Her Nazarites were purer than snow, they were whiter than milk, they were more ruddy in body than rubies, their polishing was of sapphire:","words":[["H5139","Her Nazarites",0,13],["H2141","were purer",14,24],["H7950","than snow",25,34],["H6705","they were whiter",36,52],["H2461","than milk",53,62],["H0119","they were more ruddy",64,84],["H6106","in body",85,92],["H6443","than rubies",93,104],["H1508","their polishing",106,121],["H5601","was of sapphire",122,137]]},"4:8":{"text":"Their visage is blacker than a coal; they are not known in the streets: their skin cleaveth to their bones; it is withered, it is become like a stick.","words":[["H8389","Their visage",0,12],["H2821","is blacker",13,23],["H7815","than a coal",24,35],["H5234","they are not known",37,55],["H2351","in the streets",56,70],["H5785","their skin",72,82],["H6821","cleaveth",83,91],["H6106","to their bones",92,106],["H3001","it is withered",108,122],["H6086","it is become like a stick",124,149]]},"4:9":{"text":"They that be slain with the sword are better than they that be slain with hunger: for these pine away, stricken through for want of the fruits of the field.","words":[["H2491","They that be slain",0,18],["H2719","with the sword",19,33],["H2896","are better",34,44],["H2491","than they that be slain",45,68],["H7458","with hunger",69,80],["H1992","for these",82,91],["H2100","pine away",92,101],["H1856","stricken",103,111],["H8570","through for want of the fruits",112,142],["H7704","of the field",143,155]]},"4:10":{"text":"The hands of the pitiful women have sodden their own children: they were their meat in the destruction of the daughter of my people.","words":[["H3027","The hands",0,9],["H7362","of the pitiful",10,24],["H0802","women",25,30],["H1310","have sodden",31,42],["H3206","their own children",43,61],["H1262","they were their meat",63,83],["H7667","in the destruction",84,102],["H1323","of the daughter",103,118],["H5971","of my people",119,131]]},"4:11":{"text":"The LORD hath accomplished his fury; he hath poured out his fierce anger, and hath kindled a fire in Zion, and it hath devoured the foundations thereof.","words":[["H3068","The LORD",0,8],["H3615","hath accomplished",9,26],["H2534","his fury",27,35],["H8210","he hath poured out",37,55],["H2740","his fierce",56,66],["H0639","anger",67,72],["H3341","and hath kindled",74,90],["H0784","a fire",91,97],["H6726","in Zion",98,105],["H0398","and it hath devoured",107,127],["H3247","the foundations",128,143]]},"4:12":{"text":"The kings of the earth, and all the inhabitants of the world, would not have believed that the adversary and the enemy should have entered into the gates of Jerusalem.","words":[["H4428","The kings",0,9],["H0776","of the earth",10,22],["H3427","and all the inhabitants",24,47],["H8398","of the world",48,60],["H0539","would not have believed",62,85],["H6862","that the adversary",86,104],["H0341","and the enemy",105,118],["H0935","should have entered",119,138],["H8179","into the gates",139,153],["H3389","of Jerusalem",154,166]]},"4:13":{"text":"For the sins of her prophets, and the iniquities of her priests, that have shed the blood of the just in the midst of her,","words":[["H2403","For the sins",0,12],["H5030","of her prophets",13,28],["H5771","and the iniquities",30,48],["H3548","of her priests",49,63],["H8210","that have shed",65,79],["H1818","the blood",80,89],["H6662","of the just",90,101],["H7130","in the midst",102,114]]},"4:14":{"text":"They have wandered as blind men in the streets, they have polluted themselves with blood, so that men could not touch their garments.","words":[["H5128","They have wandered",0,18],["H5787","as blind",19,27],["H2351","men in the streets",28,46],["H1351","they have polluted",48,66],["H1818","themselves with blood",67,88],["H3201","so that men could",90,107],["H3808","not",108,111],["H5060","touch",112,117],["H3830","their garments",118,132]]},"4:15":{"text":"They cried unto them, Depart ye; it is unclean; depart, depart, touch not: when they fled away and wandered, they said among the heathen, They shall no more sojourn there.","words":[["H7121","They cried",0,10],["H5493","unto them, Depart",11,28],["H2931","ye; it is unclean",29,46],["H5493","depart",48,54],["H5493","depart",56,62],["H5060","touch",64,69],["H5132","not: when they fled away",70,94],["H5128","and wandered",95,107],["H0559","they said",109,118],["H1471","among the heathen",119,136],["H3254","They shall no more",138,156],["H1481","sojourn",157,164]]},"4:16":{"text":"The anger of the LORD hath divided them; he will no more regard them: they respected not the persons of the priests, they favoured not the elders.","words":[["H6440","The anger",0,9],["H3068","of the LORD",10,21],["H2505","hath divided",22,34],["H3254","them; he will no more",35,56],["H5027","regard",57,63],["H5375","them: they respected",64,84],["H6440","not the persons",85,100],["H3548","of the priests",101,115],["H2603","they favoured",117,130],["H2205","not the elders",131,145]]},"4:17":{"text":"As for us, our eyes as yet failed for our vain help: in our watching we have watched for a nation that could not save us.","words":[["H5869","As for us, our eyes",0,19],["H3615","as yet failed",20,33],["H1892","for our vain",34,46],["H5833","help",47,51],["H6836","in our watching",53,68],["H6822","we have watched",69,84],["H1471","for a nation",85,97],["H3467","that could not save",98,117]]},"4:18":{"text":"They hunt our steps, that we cannot go in our streets: our end is near, our days are fulfilled; for our end is come.","words":[["H6679","They hunt",0,9],["H6806","our steps",10,19],["H3212","that we cannot go",21,38],["H7339","in our streets",39,53],["H7093","our end",55,62],["H7126","is near",63,70],["H3117","our days",72,80],["H4390","are fulfilled",81,94],["H7093","for our end",96,107],["H0935","is come",108,115]]},"4:19":{"text":"Our persecutors are swifter than the eagles of the heaven: they pursued us upon the mountains, they laid wait for us in the wilderness.","words":[["H7291","Our persecutors",0,15],["H7031","are swifter",16,27],["H5404","than the eagles",28,43],["H8064","of the heaven",44,57],["H1814","they pursued",59,71],["H2022","us upon the mountains",72,93],["H0693","they laid wait",95,109],["H4057","for us in the wilderness",110,134]]},"4:20":{"text":"The breath of our nostrils, the anointed of the LORD, was taken in their pits, of whom we said, Under his shadow we shall live among the heathen.","words":[["H7307","The breath",0,10],["H0639","of our nostrils",11,26],["H4899","the anointed",28,40],["H3068","of the LORD",41,52],["H3920","was taken",54,63],["H7825","in their pits",64,77],["H0559","of whom we said",79,94],["H6738","Under his shadow",96,112],["H2421","we shall live",113,126],["H1471","among the heathen",127,144]]},"4:21":{"text":"Rejoice and be glad, O daughter of Edom, that dwellest in the land of Uz; the cup also shall pass through unto thee: thou shalt be drunken, and shalt make thyself naked.","words":[["H7797","Rejoice",0,7],["H8055","and be glad",8,19],["H1323","O daughter",21,31],["H0123","of Edom",32,39],["H3427","that dwellest",41,54],["H0776","in the land",55,66],["H5780","of Uz",67,72],["H3563","the cup",74,81],["H5674","also shall pass",82,97],["H7937","through unto thee: thou shalt be drunken",98,138],["H6168","and shalt make thyself naked",140,168]]},"4:22":{"text":"The punishment of thine iniquity is accomplished, O daughter of Zion; he will no more carry thee away into captivity: he will visit thine iniquity, O daughter of Edom; he will discover thy sins.","words":[["H5771","The punishment of thine iniquity",0,32],["H8552","is accomplished",33,48],["H1323","O daughter",50,60],["H6726","of Zion",61,68],["H3254","he will no more",70,85],["H1540","carry thee away into captivity",86,116],["H6485","he will visit",118,131],["H5771","thine iniquity",132,146],["H1323","O daughter",148,158],["H0123","of Edom",159,166],["H1540","he will discover",168,184],["H2403","thy sins",185,193]]},"5:1":{"text":"Remember, O LORD, what is come upon us: consider, and behold our reproach.","words":[["H2142","Remember",0,8],["H3068","O LORD",10,16],["H5027","what is come upon us: consider",18,48],["H7200","and behold",50,60],["H2781","our reproach",61,73]]},"5:2":{"text":"Our inheritance is turned to strangers, our houses to aliens.","words":[["H5159","Our inheritance",0,15],["H2015","is turned",16,25],["H2114","to strangers",26,38],["H1004","our houses",40,50],["H5237","to aliens",51,60]]},"5:3":{"text":"We are orphans and fatherless, our mothers are as widows.","words":[["H3490","We are orphans",0,14],["H0369","and fatherless",15,29],["H0001","and fatherless",15,29],["H0517","our mothers",31,42],["H0490","are as widows",43,56]]},"5:4":{"text":"We have drunken our water for money; our wood is sold unto us.","words":[["H8354","We have drunken",0,15],["H4325","our water",16,25],["H3701","for money",26,35],["H6086","our wood",37,45],["H0935","is sold",46,53],["H4242","is sold",46,53]]},"5:5":{"text":"Our necks are under persecution: we labour, and have no rest.","words":[["H6677","Our necks",0,9],["H7291","are under persecution",10,31],["H3021","we labour",33,42],["H5117","and have no rest",44,60]]},"5:6":{"text":"We have given the hand to the Egyptians, and to the Assyrians, to be satisfied with bread.","words":[["H5414","We have given",0,13],["H3027","the hand",14,22],["H4714","to the Egyptians",23,39],["H0804","and to the Assyrians",41,61],["H7646","to be satisfied",63,78],["H3899","with bread",79,89]]},"5:7":{"text":"Our fathers have sinned, and are not; and we have borne their iniquities.","words":[["H0001","Our fathers",0,11],["H2398","have sinned",12,23],["H0369","and are not",25,36],["H5445","and we have borne",38,55],["H5771","their iniquities",56,72]]},"5:8":{"text":"Servants have ruled over us: there is none that doth deliver us out of their hand.","words":[["H5650","Servants",0,8],["H4910","have ruled",9,19],["H6561","over us: there is none that doth deliver",20,60],["H3027","us out of their hand",61,81]]},"5:9":{"text":"We gat our bread with the peril of our lives because of the sword of the wilderness.","words":[["H0935","We gat",0,6],["H3899","our bread",7,16],["H5315","with the peril of our lives",17,44],["H6440","because",45,52],["H2719","of the sword",53,65],["H4057","of the wilderness",66,83]]},"5:10":{"text":"Our skin was black like an oven because of the terrible famine.","words":[["H5785","Our skin",0,8],["H3648","was black",9,18],["H8574","like an oven",19,31],["H6440","because",32,39],["H2152","of the terrible",40,55],["H7458","famine",56,62]]},"5:11":{"text":"They ravished the women in Zion, and the maids in the cities of Judah.","words":[["H6031","They ravished",0,13],["H0802","the women",14,23],["H6726","in Zion",24,31],["H1330","and the maids",33,46],["H5892","in the cities",47,60],["H3063","of Judah",61,69]]},"5:12":{"text":"Princes are hanged up by their hand: the faces of elders were not honoured.","words":[["H8269","Princes",0,7],["H8518","are hanged up",8,21],["H3027","by their hand",22,35],["H6440","the faces",37,46],["H2205","of elders",47,56],["H1921","were not honoured",57,74]]},"5:13":{"text":"They took the young men to grind, and the children fell under the wood.","words":[["H5375","They took",0,9],["H0970","the young men",10,23],["H2911","to grind",24,32],["H5288","and the children",34,50],["H3782","fell",51,55],["H6086","under the wood",56,70]]},"5:14":{"text":"The elders have ceased from the gate, the young men from their musick.","words":[["H2205","The elders",0,10],["H7673","have ceased",11,22],["H8179","from the gate",23,36],["H0970","the young men",38,51],["H5058","from their musick",52,69]]},"5:15":{"text":"The joy of our heart is ceased; our dance is turned into mourning.","words":[["H4885","The joy",0,7],["H3820","of our heart",8,20],["H7673","is ceased",21,30],["H4234","our dance",32,41],["H2015","is turned",42,51],["H0060","into mourning",52,65]]},"5:16":{"text":"The crown is fallen from our head: woe unto us, that we have sinned!","words":[["H5850","The crown",0,9],["H5307","is fallen",10,19],["H7218","from our head",20,33],["H0188","woe",35,38],["H2398","unto us, that we have sinned",39,67]]},"5:17":{"text":"For this our heart is faint; for these things our eyes are dim.","words":[["H3820","For this our heart",0,18],["H1739","is faint",19,27],["H5869","for these things our eyes",29,54],["H2821","are dim",55,62]]},"5:18":{"text":"Because of the mountain of Zion, which is desolate, the foxes walk upon it.","words":[["H2022","Because of the mountain",0,23],["H6726","of Zion",24,31],["H8074","which is desolate",33,50],["H7776","the foxes",52,61],["H1980","walk",62,66]]},"5:19":{"text":"Thou, O LORD, remainest for ever; thy throne from generation to generation.","words":[["H3068","Thou, O LORD",0,12],["H3427","remainest",14,23],["H5769","for ever",24,32],["H3678","thy throne",34,44],["H1755","from generation",45,60],["H1755","to generation",61,74]]},"5:20":{"text":"Wherefore dost thou forget us for ever, and forsake us so long time?","words":[["H7911","Wherefore dost thou forget",0,26],["H5331","us for ever",27,38],["H5800","and forsake",40,51],["H0753","us so long",52,62],["H3117","time",63,67]]},"5:21":{"text":"Turn thou us unto thee, O LORD, and we shall be turned; renew our days as of old.","words":[["H7725","Turn",0,4],["H3068","thou us unto thee, O LORD",5,30],["H7725","and we shall be turned",32,54],["H2318","renew",56,61],["H3117","our days",62,70],["H6924","as of old",71,80]]},"5:22":{"text":"But thou hast utterly rejected us; thou art very wroth against us.","words":[["H3988","But thou hast utterly",0,21],["H3988","rejected",22,30],["H3966","us; thou art very",31,48],["H7107","wroth",49,54]]}}};
